1	//! Pipeline coordinator: drain audio ringbuffer on an OS thread, run wake/VAD, queue STT jobs,
2	//! and emit stdout JSONL transcript events.
3	//!
4	//! Thread topology (locked):
5	//! - CPAL RT callback: push samples to ringbuf (no alloc/no block)
6	//! - Pipeline thread (OS): drain ringbuf; run wake + VAD segmentation; enqueue utterance jobs
7	//! - STT thread (OS): whisper-rs inference
8	//! - Output thread (OS): write JSONL to stdout (only stdout writer)
9	
10	use anyhow::{Context, Result};
11	use ringbuf::traits::Consumer;
12	use std::sync::{
13	    atomic::{AtomicBool, Ordering},
14	    Arc,
15	};
16	use std::time::{Duration, Instant};
17	use tokio_util::sync::CancellationToken;
18	
19	use ringbuf::HeapCons;
20	use crate::config::{Config, PipelineVerbosity};
21	use crate::pipeline::dispatcher::DispatchOutcome;
22	use crate::pipeline::jsonl::{JsonlVerbosity, JsonlWriter};
23	use crate::stt::{SttResult, SttService};
24	// Alias for readability: this module builds segmentation configs, not generic VAD configs.
25	use crate::vad::{VadConfig as SegCfg, VadSegmenter, FRAME_SAMPLES};
26	use crate::wake::WakeWord;
27	
28	/// Messages flowing from the dispatcher thread to the output thread.
29	enum OutputMsg {
30	    Utterance(SttResult),
31	    Dispatched { utterance_id: u64, macro_id: String, score: f32 },
32	    NoMatch { utterance_id: u64, transcript: String },
33	}
34	
35	pub struct PipelineHandles {
36	    pub pipeline: std::thread::JoinHandle<()>,
37	    pub output: std::thread::JoinHandle<()>,
38	    pub stt: Option<SttService>,
39	    pub dispatcher: Arc<crate::pipeline::dispatcher::Dispatcher>,
40	}
41	
42	/// Spawn the pipeline worker threads.
43	///
44	/// CRITICAL: do NOT pass the full `AudioHandle` here — callers must keep the
45	/// `StreamGuard` on the main thread (see `src/audio/mod.rs` for rationale).
46	/// Only the ringbuf `consumer` end should be forwarded into the worker.
47	pub fn spawn_pipeline(
48	    audio_consumer: HeapCons<f32>,
49	    config: Config,
50	    ptt_active: Arc<AtomicBool>,
51	    muted: Arc<AtomicBool>,
52	    macro_tx: std::sync::mpsc::Sender<crate::input::inject::MacroCmd>,
53	    shutdown: CancellationToken,
54	) -> Result<PipelineHandles> {
55	    let listen_window = Duration::from_secs(config.pipeline.listen_window_secs);
56	    // Wake pre-roll: keep a short rolling buffer of audio while idle so the first
57	    // post-wake command doesn't lose its leading syllables.
58	    //
59	    // NOTE: this is separate from VAD's own preroll (which only applies once
60	    // LISTENING is active). This buffer is used to "seed" the VAD segmenter at
61	    // the moment wake triggers.
62	    const WAKE_PREROLL_MS: u64 = 600;
63	    let wake_preroll_frames: usize = WAKE_PREROLL_MS.div_ceil(20) as usize;
64	
65	    // Build VAD config from config file.
66	    let ms_to_frames = |ms: u64| ms.div_ceil(20).max(1) as usize;
67	    let seg_cfg = SegCfg {
68	        start_threshold: config.vad.start_threshold,
69	        stop_threshold: config.vad.stop_threshold,
70	        min_speech_frames: ms_to_frames(config.vad.min_speech_ms),
71	        end_silence_frames: ms_to_frames(config.vad.end_silence_ms),
72	        preroll_frames: config.vad.preroll_ms.div_ceil(20) as usize,
73	        tail_frames: config.vad.tail_ms.div_ceil(20) as usize,
74	        max_utterance_frames: (config.vad.max_utterance_secs as usize) * 50, // 50 frames/sec
75	    };
76	
77	    // Wake mode wants “snappy” commands, not conservative segmentation.
78	    // Override a few knobs inside the wake LISTENING window to reduce end-of-speech
79	    // latency. Keep thresholds same as base VAD config.
80	    //
81	    // Targets:
82	    // - end_silence_ms smaller to cut earlier after last word
83	    // - min_speech_ms smaller to accept short commands
84	    // - tail/preroll smaller (wake pre-roll already handled separately)
85	    // - cap utterance length smaller for wake commands
86	    const WAKE_END_SILENCE_MS: u64 = 150;
87	    const WAKE_MIN_SPEECH_MS: u64 = 60;
88	    const WAKE_VAD_PREROLL_MS: u64 = 80;
89	    const WAKE_VAD_TAIL_MS: u64 = 80;
90	    const WAKE_MAX_UTTERANCE_SECS: usize = 4;
91	    const WAKE_FORCE_FLUSH_MS: u64 = 1200;
92	    let seg_cfg_wake = SegCfg {
93	        start_threshold: seg_cfg.start_threshold,
94	        // End speech sooner in noisy environments (wake commands are short).
95	        stop_threshold: (seg_cfg.start_threshold - 0.05).max(seg_cfg.stop_threshold),
96	        min_speech_frames: ms_to_frames(WAKE_MIN_SPEECH_MS),
97	        end_silence_frames: ms_to_frames(WAKE_END_SILENCE_MS),
98	        preroll_frames: ms_to_frames(WAKE_VAD_PREROLL_MS),
99	        tail_frames: ms_to_frames(WAKE_VAD_TAIL_MS),
100	        max_utterance_frames: WAKE_MAX_UTTERANCE_SECS * 50,
101	    };
102	
103	    // Output thread owns stdout writer and ensures stdout remains JSONL-only.
104	    let (out_tx, out_rx) = crossbeam_channel::bounded::<OutputMsg>(16);
105	
106	    // Dispatcher thread receives STT results, runs macros, then forwards to JSONL output
107	    let (dispatch_tx, dispatch_rx) = crossbeam_channel::bounded::<SttResult>(8);
108	    let dispatch_rx_for_drop = dispatch_rx.clone();
109	
110	    let dispatcher = Arc::new(crate::pipeline::dispatcher::Dispatcher::new(
111	        config.stt.confidence_threshold,
112	        config.macros.clone(),
113	        macro_tx,
114	        config.timing.dwell_ms,
115	        config.timing.gap_ms,
116	    ));
117	    let dispatcher_for_thread = Arc::clone(&dispatcher);
118	    let dispatcher_shutdown = shutdown.clone();
119	    let dispatch_out_tx = out_tx.clone();
120	    std::thread::spawn(move || {
121	        tracing::info!("Dispatcher thread started");
122	        while !dispatcher_shutdown.is_cancelled() {
123	            match dispatch_rx.recv_timeout(Duration::from_millis(50)) {
124	                Ok(r) => {
125	                    let utterance_id = r.utterance_id;
126	                    let transcript = r.text.clone();
127	                    match dispatcher_for_thread.process(&r.text) {
128	                        DispatchOutcome::Fired { macro_id, score } => {
129	                            let _ = dispatch_out_tx.send(OutputMsg::Dispatched { utterance_id, macro_id, score });
130	                        }
131	                        DispatchOutcome::NoMatch => {
132	                            let _ = dispatch_out_tx.send(OutputMsg::NoMatch { utterance_id, transcript });
133	                        }
134	                    }
135	                    let _ = dispatch_out_tx.send(OutputMsg::Utterance(r));
136	                }
137	                Err(crossbeam_channel::RecvTimeoutError::Timeout) => continue,
138	                Err(crossbeam_channel::RecvTimeoutError::Disconnected) => break,
139	            }
140	        }
141	        tracing::info!("Dispatcher thread stopped");
142	    });
143	
144	    let jsonl_verbosity = match config.pipeline.verbosity {
145	        PipelineVerbosity::Summary => JsonlVerbosity::SummaryOnly,
146	        PipelineVerbosity::Stages => JsonlVerbosity::Stages,
147	    };
148	
149	    let output_shutdown = shutdown.clone();
150	    let output = std::thread::spawn(move || {
151	        let stdout = std::io::stdout();
152	        let mut w = JsonlWriter::new(stdout.lock(), jsonl_verbosity);
153	
154	        // Emit a startup event to force a flush and verify stdout is working (D-19).
155	        if let Err(e) = w.write_event(&crate::pipeline::jsonl::JsonlEvent::Status {
156	            message: "pipeline_started",
157	            mono_ms: 0,
158	        }) {
159	            tracing::error!("Failed to write startup JSONL: {e}");
160	        }
161	
162	        while !output_shutdown.is_cancelled() {
163	            match out_rx.recv_timeout(Duration::from_millis(50)) {
164	                Ok(OutputMsg::Utterance(mut r)) => {
165	                    r.timings.mark_output_done();
166	                    if let Err(e) = w.write_utterance(
167	                        r.utterance_id,
168	                        &r.text,
169	                        r.audio_ms,
170	                        r.stt_ms,
171	                        r.timings,
172	                        r.start_frame_idx,
173	                        r.end_frame_idx,
174	                    ) {
175	                        tracing::error!("Failed to write stdout JSONL: {e}");
176	                    }
177	                }
178	                Ok(OutputMsg::Dispatched { utterance_id, macro_id, score }) => {
179	                    if let Err(e) = w.write_dispatch(utterance_id, &macro_id, score) {
180	                        tracing::error!("Failed to write dispatch JSONL: {e}");
181	                    }
182	                }
183	                Ok(OutputMsg::NoMatch { utterance_id, transcript }) => {
184	                    if let Err(e) = w.write_no_match(utterance_id, &transcript) {
185	                        tracing::error!("Failed to write no_match JSONL: {e}");
186	                    }
187	                }
188	                Err(crossbeam_channel::RecvTimeoutError::Timeout) => continue,
189	                Err(crossbeam_channel::RecvTimeoutError::Disconnected) => break,
190	            }
191	        }
192	    });
193	
194	    // STT service (optional, feature-gated) is created before threads (fail-fast).
195	    let stt: Option<SttService> = if config.stt.enabled {
196	        let model_path = config
197	            .stt
198	            .model_path
199	            .as_ref()
200	            .context("stt.enabled but stt.model_path is not set")?;
201	
202	        #[cfg(not(feature = "stt"))]
203	        {
204	            let _ = model_path;
205	            return Err(anyhow::anyhow!(
206	                "Config enables STT, but this build was compiled without `--features stt`."
207	            ));
208	        }
209	
210	        #[cfg(feature = "stt")]
211	        {
212	            Some(
213	                SttService::new(model_path, config.stt.initial_prompt.clone(), shutdown.clone())
214	                    .context("create STT service")?
215	                    .spawn()
216	                    .context("spawn STT thread")?,
217	            )
218	        }
219	    } else {
220	        None
221	    };
222	
223	    let stt_submit = stt.as_ref().map(|s| s.submitter());
224	    let stt_results = stt.as_ref().map(|s| s.result_receiver());
225	
226	    // Wake word (optional). Construct before pipeline loop (fail-fast).
227	    let wake = if config.wake.enabled {
228	        Some(WakeWord::new(&config.wake).context("init wake word")?)
229	    } else {
230	        None
231	    };
232	
233	    // ORT_DYLIB_PATH auto-discovery: point the `ort` crate at the same
234	    // libonnxruntime.so that sherpa-onnx ships (shared feature), so both
235	    // runtimes share one ORT global environment instead of colliding.
236	    // Respect any existing user-supplied value.
237	    if std::env::var_os("ORT_DYLIB_PATH").is_none() {
238	        if let Ok(exe) = std::env::current_exe() {
239	            if let Some(exe_dir) = exe.parent() {
240	                let so_path = exe_dir.join("libonnxruntime.so");
241	                // SAFETY: single-threaded at this point — no pipeline threads spawned yet.
242	                unsafe { std::env::set_var("ORT_DYLIB_PATH", &so_path) };
243	                tracing::info!(path = %so_path.display(), "ORT_DYLIB_PATH auto-set to sherpa-onnx shared library");
244	            }
245	        }
246	    }
247	
248	    // VAD model is required for utterance segmentation (CPU-only baseline, D-16).
249	    //
250	    // IMPORTANT: `ort` (ONNX Runtime) can panic at runtime if `libonnxruntime.so`
251	    // is not discoverable. Convert that into a normal, actionable startup error
252	    // instead of crashing the process.
253	    let start_vad = std::time::Instant::now();
254	    let mut silero = std::panic::catch_unwind(|| {
255	        silero_vad_rust::silero_vad::model::load_silero_vad_with_options(
256	            silero_vad_rust::silero_vad::model::LoadOptions {
257	                force_onnx_cpu: true,
258	                ..Default::default()
259	            },
260	        )
261	    })
262	    .map_err(|_| {
263	        anyhow::anyhow!(
264	            "Failed to load Silero VAD: ONNX Runtime could not be loaded.\n\
265	             Fix: install ONNX Runtime so `libonnxruntime.so` is in your library path, or set ORT_DYLIB_PATH to the full path of `libonnxruntime.so`.\n\
266	             Example (Arch/CachyOS): `sudo pacman -S onnxruntime`"
267	        )
268	    })?
269	    .context("load silero VAD model")?;
270	    tracing::info!("Silero VAD loaded in {}ms", start_vad.elapsed().as_millis());
271	
272	    // NOTE: the CPAL stream guard is intentionally NOT in this function — the
273	    // caller (main) keeps it alive. We only own the ringbuf consumer end.
274	    let pipeline_shutdown = shutdown.clone();
275	
276	    let pipeline = std::thread::spawn(move || {
277	        tracing::info!("Pipeline thread started");
278	
279	        let mut seg = VadSegmenter::new(seg_cfg.clone());
280	        let mut consumer = audio_consumer;
281	
282	        let mut pending = Vec::<f32>::with_capacity(FRAME_SAMPLES * 8);
283	        let mut pending_idx: usize = 0;
284	        let mut tmp = [0.0f32; 1024];
285	        let mut frame = [0.0f32; FRAME_SAMPLES];
286	
287	        let mut listening_until: Option<Instant> = None;
288	        let mut listening_started_at: Option<Instant> = None;
289	        let mut prev_ptt = false;
290	
291	        // Rolling wake pre-roll ring: N frames of 20ms each.
292	        let mut wake_preroll: Vec<[f32; FRAME_SAMPLES]> =
293	            vec![[0.0; FRAME_SAMPLES]; wake_preroll_frames.max(1)];
294	        let mut wake_preroll_pos: usize = 0; // next write index
295	        let mut wake_preroll_len: usize = 0; // valid frames in ring (<= capacity)
296	
297	        // Heartbeat: log samples/frames received every 5s to confirm audio is flowing.
298	        let mut heartbeat_samples: usize = 0;
299	        let mut heartbeat_last = Instant::now();
300	
301	        // PTT-mode direct capture: all audio while PTT is held lands here.
302	        // On release the entire buffer is sent to STT unconditionally, bypassing
303	        // the VAD speech-gate. VAD is still used for the wake-word listen window.
304	        let mut ptt_audio: Vec<f32> = Vec::with_capacity(FRAME_SAMPLES * 200); // ~4 sec
305	        let mut ptt_utterance_id: u64 = 0;
306	        let mut ptt_next_id: u64 = 1; // monotonic ID counter for PTT utterances
307	        let mut ptt_timings = crate::pipeline::timing::UtteranceTimings::new();
308	        let mut ptt_start_frame: u64 = 0;
309	        let mut ptt_frame_count: u64 = 0;
310	
311	        while !pipeline_shutdown.is_cancelled() {
312	            // Always drain completed STT results first so they are never lost regardless
313	            // of PTT state.  Previously this was inside the VAD branch and was skipped by
314	            // `continue` while PTT was idle, causing results to accumulate forever.
315	            if let Some(stt_results) = &stt_results {
316	                while let Ok(r) = stt_results.try_recv() {
317	                    if crate::vad::try_send_drop_oldest(&dispatch_tx, &dispatch_rx_for_drop, r).is_err() {
318	                        break;
319	                    }
320	                }
321	            }
322	
323	            // Drain some samples from ringbuf.
324	            let n = consumer.pop_slice(&mut tmp);
325	            if n == 0 {
326	                std::thread::sleep(Duration::from_millis(5));
327	            } else {
328	                pending.extend_from_slice(&tmp[..n]);
329	                heartbeat_samples += n;
330	            }
331	
332	            // Periodic heartbeat so we can confirm audio is flowing (or diagnose silence).
333	            if heartbeat_last.elapsed() >= Duration::from_secs(5) {
334	                tracing::debug!(samples = heartbeat_samples, "pipeline heartbeat: audio samples received in last 5s");
335	                heartbeat_samples = 0;
336	                heartbeat_last = Instant::now();
337	            }
338	
339	            // Compact pending buffer occasionally.
340	            if pending_idx > FRAME_SAMPLES * 16 {
341	                pending.drain(0..pending_idx);
342	                pending_idx = 0;
343	            }
344	
345	            while pending.len().saturating_sub(pending_idx) >= FRAME_SAMPLES {
346	                frame.copy_from_slice(&pending[pending_idx..pending_idx + FRAME_SAMPLES]);
347	                pending_idx += FRAME_SAMPLES;
348	
349	                let now = Instant::now();
350	                let ptt = ptt_active.load(Ordering::Relaxed);
351	                let listening = listening_until.map(|t| now < t).unwrap_or(false);
352	
353	                // Mute gate: drop frame and reset any in-progress state.
354	                if muted.load(Ordering::Relaxed) {
355	                    if prev_ptt { prev_ptt = false; }
356	                    if listening_until.is_some() {
357	                        listening_until = None;
358	                        listening_started_at = None;
359	                        wake_preroll_len = 0;
360	                        seg = VadSegmenter::new(seg_cfg.clone());
361	                    }
362	                    continue;
363	                }
364	
365	                // PTT pressed: start or continue recording directly into ptt_audio.
366	                if ptt {
367	                    if !prev_ptt {
368	                        // Rising edge: begin new PTT utterance.
369	                        ptt_audio.clear();
370	                        ptt_utterance_id = ptt_next_id;
371	                        ptt_next_id += 1;
372	                        ptt_timings = crate::pipeline::timing::UtteranceTimings::new();
373	                        ptt_start_frame = ptt_frame_count;
374	                        tracing::debug!(utterance_id = ptt_utterance_id, "PTT utterance started");
375	                    }
376	                    ptt_audio.extend_from_slice(&frame);
377	                    ptt_frame_count += 1;
378	                    prev_ptt = true;
379	                    continue;
380	                }
381	
382	                // PTT just released: send entire PTT buffer to STT.
383	                if prev_ptt {
384	                    let audio_len = ptt_audio.len();
385	                    let min_samples = (crate::vad::SAMPLE_RATE_HZ as usize) / 10; // 100 ms minimum
386	                    tracing::debug!(
387	                        utterance_id = ptt_utterance_id,
388	                        samples = audio_len,
389	                        "PTT released – submitting to STT"
390	                    );
391	                    if audio_len >= min_samples {
392	                        // For PTT captures we bypass VAD, but we still want a stable
393	                        // monotonic milestone so latency fields are meaningful.
394	                        ptt_timings.mark_vad_done();
395	                        let job = crate::vad::UtteranceJob {
396	                            utterance_id: ptt_utterance_id,
397	                            audio: std::mem::take(&mut ptt_audio),
398	                            timings: ptt_timings,
399	                            start_frame_idx: ptt_start_frame,
400	                            end_frame_idx: ptt_frame_count,
401	                        };
402	                        if let Some(stt_submit) = &stt_submit {
403	                            if let Err(e) = stt_submit.try_submit(job) {
404	                                tracing::warn!(utterance_id = ptt_utterance_id, "STT submit failed: {e}");
405	                            }
406	                        }
407	                    } else {
408	                        tracing::debug!(utterance_id = ptt_utterance_id, samples = audio_len, "PTT too short, skipping STT");
409	                        ptt_audio.clear();
410	                    }
411	                    // Reset the VAD segmenter so stale state doesn't bleed into
412	                    // the next wake-word listen window.
413	                    seg = VadSegmenter::new(seg_cfg.clone());
414	                }
415	                prev_ptt = false;
416	
417	                // Wake-word detection while idle (no PTT) to enter LISTENING (D-17/D-18).
418	                if !ptt && !listening {
419	                    if let Some(w) = &wake {
420	                        // Maintain rolling pre-roll while idle so we can seed VAD
421	                        // immediately when wake triggers.
422	                        wake_preroll[wake_preroll_pos] = frame;
423	                        wake_preroll_pos = (wake_preroll_pos + 1) % wake_preroll.len();
424	                        wake_preroll_len = wake_preroll_len.saturating_add(1).min(wake_preroll.len());
425	
426	                        w.accept_audio(16_000, &frame);
427	                        w.decode_until_not_ready();
428	                        if let Some(keyword) = w.take_keyword() {
429	                            tracing::info!(keyword = %keyword, "Wake word triggered; entering LISTENING window");
430	                            listening_until = Some(now + listen_window);
431	                            listening_started_at = Some(now);
432	                            w.reset();
433	                            // Seed VAD with pre-roll frames captured while idle.
434	                            // This helps include the first command word if it started
435	                            // right before the wake trigger fired.
436	                            seg = VadSegmenter::new(seg_cfg_wake.clone());
437	                            if wake_preroll_len > 0 {
438	                                let cap = wake_preroll.len();
439	                                let start = (wake_preroll_pos + cap - wake_preroll_len) % cap;
440	                                for i in 0..wake_preroll_len {
441	                                    let idx = (start + i) % cap;
442	                                    let _ = seg.push_frame_silero(&mut silero, &wake_preroll[idx]);
443	                                }
444	                            }
445	                            // Also feed current frame into VAD below (do not `continue`).
446	                        } else {
447	                            continue;
448	                        }
449	                    } else {
450	                        continue;
451	                    }
452	                }
453	
454	                // Wake-word listen window: run VAD segmentation.
455	                match seg.push_frame_silero(&mut silero, &frame) {
456	                    Ok(Some(mut job)) => {
457	                        job.timings.mark_vad_done();
458	
459	                        if let Some(stt_submit) = &stt_submit {
460	                            if let Err(e) = stt_submit.try_submit(job) {
461	                                tracing::warn!("STT submit failed: {e}");
462	                            }
463	                        }
464	                    }
465	                    Ok(None) => {}
466	                    Err(e) => tracing::warn!("VAD error: {e}"),
467	                }
468	
469	                // Wake mode fallback: if VAD never observes "enough silence" due to
470	                // noise/AGC, force-flush after a short budget once LISTENING started.
471	                if listening {
472	                    if let Some(t0) = listening_started_at {
473	                        if t0.elapsed() >= Duration::from_millis(WAKE_FORCE_FLUSH_MS) {
474	                            if let Some(mut job) = seg.force_flush() {
475	                                tracing::debug!(
476	                                    utterance_id = job.utterance_id,
477	                                    "Wake force-flush after {}ms",
478	                                    WAKE_FORCE_FLUSH_MS
479	                                );
480	                                job.timings.mark_vad_done();
481	                                if let Some(stt_submit) = &stt_submit {
482	                                    if let Err(e) = stt_submit.try_submit(job) {
483	                                        tracing::warn!("STT submit failed: {e}");
484	                                    }
485	                                }
486	                            }
487	                            // Reset timer so we don't spam force_flush.
488	                            listening_started_at = Some(now);
489	                        }
490	                    }
491	                }
492	
493	                // If LISTENING window expired, reset wake pre-roll so next command
494	                // doesn't get polluted by prior-window audio.
495	                if listening_until.map(|t| now >= t).unwrap_or(false) {
496	                    listening_until = None;
497	                    listening_started_at = None;
498	                    wake_preroll_len = 0;
499	                    seg = VadSegmenter::new(seg_cfg.clone());
500	                }
501	            }
502	        }
503	
504	        tracing::info!("Pipeline thread stopped");
505	    });
506	
507	    Ok(PipelineHandles { pipeline, output, stt, dispatcher })
508	}
